function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const INF = 1e9;
    const dist: number[][][] = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(k + 1).fill(INF)));
    dist[0][0][0] = 0;

    const dirs = [[0, 1], [1, 0]]; // right, down

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            for (let t = 0; t <= k; t++) {
                if (dist[i][j][t] == INF) continue;

                // Regular move: right or down
                for (const [dx, dy] of dirs) {
                    const ni = i + dx;
                    const nj = j + dy;
                    if (ni < m && nj < n) {
                        dist[ni][nj][t] = Math.min(dist[ni][nj][t], dist[i][j][t] + grid[ni][nj]);
                    }
                }

                // Teleport: find all cells with value <= current cell's value
                for (let x = 0; x < m; x++) {
                    for (let y = 0; y < n; y++) {
                        if (grid[x][y] <= grid[i][j] && x != i || y != j) {
                            if (t < k) {
                                dist[x][y][t + 1] = Math.min(dist[x][y][t + 1], dist[i][j][t]);
                            }
                        }
                    }
                }
            }
        }
    }

    let res = INF;
    for (let t = 0; t <= k; t++) {
        res = Math.min(res, dist[m - 1][n - 1][t]);
    }

    return res;
}

